fs.promises.readFile(path.join(__dirname, "lib/knowledge/sichuan-attractions.json"), "utf-8")
  .then((data) => { _sichuanAttractions = JSON.parse(data); console.log("[kb] sichuan-attractions preloaded"); })
  .catch(() => { _sichuanAttractions = {}; });

function getSichuanAttractions() {
  if (!_sichuanAttractions) {
    // Sync fallback: only reached if async hasn't finished (sub-second race at startup)
    try {
      _sichuanAttractions = JSON.parse(
        fs.readFileSync(path.join(__dirname, "lib/knowledge/sichuan-attractions.json"), "utf-8")
      );
    } catch { _sichuanAttractions = {}; }
  }
  return _sichuanAttractions;
}

/**
 * Search Sichuan attraction data by city and/or keyword.
 * Returns top `limit` sorted by rating desc.
 */
// P2-02/CT-03: BM25 index cache — rebuilt when attractions data changes
let _bm25IndexCache = null;
let _bm25DocsCache = null;

function _getBm25Index(docs) {
  if (_bm25IndexCache && _bm25DocsCache === docs) return _bm25IndexCache;
  _bm25DocsCache = docs;
  _bm25IndexCache = _bm25BuildIndex(docs, ["name", "intro", "tips", "season", "address"]);
  return _bm25IndexCache;
}

function searchAttractions({ city = "", keyword = "", limit = 8 } = {}) {
  const db = getSichuanAttractions();

  // Determine which city buckets to search
  let buckets = [];
  if (city) {
    const cityKey = Object.keys(db).find((k) =>
      k === city || city.includes(k) || k.includes(city)
    );
    if (cityKey) buckets = [db[cityKey]];
  }
  if (!buckets.length) buckets = Object.values(db); // search all

  let results = buckets.flat();

  if (keyword && results.length > 0) {
    // CT-03/P2-02: BM25 relevance ranking replaces pure string matching
    const index = _getBm25Index(results);
    results = _bm25Rank(keyword, results, index, { ratingBoost: 0.3 });
    // For BM25, take top N (already sorted by relevance score)
  } else {
    // No keyword: sort by rating desc
    results = results.sort((a, b) => (b.rating || 0) - (a.rating || 0));
  }

  // Sort by rating desc, take top N
  return results
    .slice(0, limit)
    .map((a) => ({
      name: a.name,
      city: a.city,
      rating: a.rating,
      address: a.address,
      hours: a.hours,
      ticket: a.ticket,
      visit_time: a.visit_time,
      season: a.season,
      intro: a.intro ? a.intro.slice(0, 200) : "",
      tips: a.tips ? a.tips.slice(0, 150) : "",
    }));
}

function loadLocalEnvFiles() {
  const loaded = [];
  const envFiles = [
    path.join(__dirname, ".env.runtime.local"),
    path.join(__dirname, ".env.local"),
    path.join(__dirname, ".env"),
  ];
  for (const filePath of envFiles) {
    if (!fs.existsSync(filePath)) continue;
    let raw = "";
    try {
      raw = fs.readFileSync(filePath, "utf8");
    } catch {
      continue;
    }
    loaded.push(filePath);
    const lines = raw.split(/\r?\n/);
    for (const lineRaw of lines) {
      const line = String(lineRaw || "").trim();
      if (!line || line.startsWith("#")) continue;
      const cleaned = line.startsWith("export ") ? line.slice(7).trim() : line;
      const idx = cleaned.indexOf("=");
      if (idx <= 0) continue;
      const key = cleaned.slice(0, idx).trim();
      if (!key || !!process.env[key]) continue;  // overwrite only if current value is falsy/empty
      let value = cleaned.slice(idx + 1).trim();
      if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
        value = value.slice(1, -1);
      }
      process.env[key] = value;
    }
  }
  return loaded;
}

LOADED_ENV_FILES = loadLocalEnvFiles();

